/**
 * Recebe items contendo campos Redis1 e Redis2 como strings JSON de arrays de mensagens.
 * Analisa ambos, une apenas as mensagens diferentes (sem duplicatas) e retorna uma única string.
 */
function mergeUniqueMessages(items) {
  // Obtém as strings brutas
  const raw1 = items[0].json.Redis1;
  const raw2 = items[0].json.Redis2;

  // Função para parsear com segurança
  function safeParse(raw) {
    if (!raw) return [];
    try {
      const parsed = JSON.parse(raw);
      return Array.isArray(parsed) ? parsed : [parsed];
    } catch {
      return [raw];
    }
  }

  // Parse das duas fontes
  const arr1 = safeParse(raw1);
  const arr2 = safeParse(raw2);

  // Une e remove duplicatas mantendo ordem de ocorrência
  const unique = [];
  [...arr1, ...arr2].forEach(msg => {
    if (!unique.includes(msg)) unique.push(msg);
  });

  // Junta numa única conversa
  const conversation = unique.join(' ');

  return [{ json: { conversation } }];
}

// No n8n Function Node, basta retornar:
return mergeUniqueMessages(items);

// Variável de entrada, idealmente verificada
const inputText = $json.output;
let messages = [];

// 1. VERIFICAÇÃO DA ENTRADA
if (typeof inputText !== 'string') {
  // Opção: retornar um erro ou um resultado padrão.
  // Exemplo: retornar mensagens vazias com um erro.
  return [{ json: { messages: [], error: "Input text ($json.output) is not a string or is missing." } }];
  // Se preferir que o script continue com uma string vazia:
  // inputText = "";
}

function isBudget(text) {
  // A verificação de 'text' como string já foi feita no início.
  const orçamentoPalavras = ['orçamento', 'escolher', 'escolhas', 'fechar', 'total geral'];
  const linhas = text.split('\n');
  let blocosDeProduto = 0;

  for (const linha of linhas) {
    if (linha.includes('por R$')) blocosDeProduto++;
  }

  // Compara as palavras chave em minúsculas para robustez
  const contemPalavraChave = orçamentoPalavras.some(p => text.toLowerCase().includes(p.toLowerCase()));
  // Verifica se "Qual dessas você prefere?" aparece pelo menos 2 vezes.
  const contemPerguntaPreferenciaMultipla = (text.split('Qual dessas você prefere?').length -1) >= 2;


  return (
    blocosDeProduto >= 3 ||
    contemPalavraChave ||
    contemPerguntaPreferenciaMultipla
  );
}

function dividirMensagemNatural(texto, limite = 200) {
  // A verificação de 'texto' como string já foi feita.
  // Se o texto estiver vazio após trim, retorna array vazio.
  if (texto.trim().length === 0) {
    return [];
  }

  // Divide o texto em sentenças (partes)
  const partes = texto
    .split(/(?<=[.!?])\s+/g) // Divide após pontuação seguida de espaço
    .map(p => p.trim()) // Remove espaços extras de cada parte
    .filter(p => p.length > 0); // Remove partes vazias

  const mensagensFinais = [];
  let bufferAtual = '';

  for (const parte of partes) {
    // CASO 1: A 'parte' (sentença) sozinha já excede o limite.
    if (parte.length > limite) {
      // Se havia algo no buffer, adiciona-o primeiro às mensagens.
      if (bufferAtual.length > 0) {
        mensagensFinais.push(bufferAtual);
        bufferAtual = ''; // Limpa o buffer
      }

      // Agora, quebra a 'parte' longa.
      // Estratégia: quebrar por palavras.
      let palavrasDaParte = parte.split(/\s+/g).filter(p => p.length > 0);
      let subParteBuffer = '';
      for (const palavra of palavrasDaParte) {
        // Se uma única palavra já excede o limite (e o sub-buffer está vazio)
        if (palavra.length > limite && subParteBuffer.length === 0) {
          mensagensFinais.push(palavra); // Adiciona a palavra longa (pode-se truncar se necessário)
          // subParteBuffer continua vazio para a próxima palavra
        }
        // Tenta adicionar a palavra ao sub-buffer atual
        else if ((subParteBuffer + (subParteBuffer ? ' ' : '') + palavra).length <= limite) {
          subParteBuffer = (subParteBuffer + (subParteBuffer ? ' ' : '') + palavra);
        }
        // Não coube, então descarrega o sub-buffer e inicia um novo com a palavra atual.
        else {
          if (subParteBuffer.length > 0) {
            mensagensFinais.push(subParteBuffer);
          }
          subParteBuffer = palavra; // Esta palavra pode ser > limite, será tratada na próxima iteração ou no push final
        }
      }
      // Adiciona o que sobrou no subParteBuffer da sentença longa
      if (subParteBuffer.length > 0) {
        mensagensFinais.push(subParteBuffer);
      }
      // O buffer principal deve estar vazio aqui, pois a 'parte' longa foi totalmente processada.
      bufferAtual = '';
    }
    // CASO 2: A 'parte' (sentença) NÃO excede o limite por si só.
    else {
      const tentativaComBuffer = (bufferAtual + (bufferAtual ? ' ' : '') + parte);
      if (tentativaComBuffer.length <= limite) {
        // Cabe no buffer atual ou com o buffer atual.
        bufferAtual = tentativaComBuffer;
      } else {
        // Não cabe com o buffer atual. Descarrega o buffer.
        if (bufferAtual.length > 0) {
          mensagensFinais.push(bufferAtual);
        }
        // A 'parte' atual (que sabemos ser <= limite) se torna o novo buffer.
        bufferAtual = parte;
      }
    }
  }

  // Adiciona o que restou no buffer no final de todas as partes.
  if (bufferAtual.length > 0) {
    mensagensFinais.push(bufferAtual);
  }

  return mensagensFinais;
}

// LÓGICA PRINCIPAL
if (isBudget(inputText)) {
  // Se for orçamento, junta tudo numa mensagem, trocando quebras de linha por espaço.
  messages.push(inputText.replace(/\n+/g, ' ').trim());
} else {
  // Senão, divide a mensagem.
  messages = dividirMensagemNatural(inputText, 200); // Limite pode ser passado aqui se diferente do default
}

return [{ json: { messages } }];

